class SecureFaceRecognitionAPI:
    def __init__(self):
        self.model = None
        self.label_encoder = None
        self.known_encodings = []
        self.known_names = []
        self.is_trained = False
        self.access_log = []
        
    def _secure_hash(self, data):
        """Secure hashing function"""
        return hashlib.sha256(data).hexdigest()
    
    def _validate_image(self, image_path):
        """Validate image file"""
        try:
            img = cv2.imread(image_path)
            if img is None:
                raise ValueError("Invalid image file")
            if img.size == 0:
                raise ValueError("Empty image file")
            return True
        except Exception as e:
            logging.error(f"Image validation failed: {str(e)}")
            return False
    
    def _secure_train(self, image_paths, names):
        """Secure training with validation"""
        if len(image_paths) != len(names):
            raise ValueError("Image paths and names must have same length")
        
        encodings = []
        valid_names = []
        
        for img_path, name in zip(image_paths, names):
            if not self._validate_image(img_path):
                logging.warning(f"Skipping invalid image: {img_path}")
                continue
                
            image = face_recognition.load_image_file(img_path)
            face_locations = face_recognition.face_locations(image)
            
            if len(face_locations) == 0:
                logging.warning(f"No face detected in image: {img_path}")
                continue
                
            if len(face_locations) > 1:
                logging.warning(f"Multiple faces detected in image: {img_path}")
                continue
                
            face_encoding = face_recognition.face_encodings(image, face_locations)[0]
            encodings.append(face_encoding)
            valid_names.append(name)
        
        if len(encodings) == 0:
            raise ValueError("No valid faces found for training")
        
        # Encode labels
        self.label_encoder = LabelEncoder()
        encoded_labels = self.label_encoder.fit_transform(valid_names)
        
        # Train model
        self.model = SVC(kernel='linear', probability=True, C=1.0)
        self.model.fit(encodings, encoded_labels)
        
        # Store known faces
        self.known_encodings = encodings
        self.known_names = valid_names
        self.is_trained = True
        
        # Save model securely
        model_data = {
            'model': self.model,
            'label_encoder': self.label_encoder,
            'known_encodings': self.known_encodings,
            'known_names': self.known_names
        }
        
        model_path = os.path.join(MODEL_DIR, f"face_model_{self._secure_hash(str(datetime.now()).encode())}.pkl")
        with open(model_path, 'wb') as f:
            pickle.dump(model_data, f)
        
        logging.info(f"Model trained successfully with {len(encodings)} faces")
        return True
    
    def _secure_predict(self, image_path):
        """Secure prediction with validation"""
        if not self.is_trained:
            raise ValueError("Model not trained")
        
        if not self._validate_image(image_path):
            raise ValueError("Invalid image file")
        
        image = face_recognition.load_image_file(image_path)
        face_locations = face_recognition.face_locations(image)
        
        if len(face_locations) == 0:
            return {"error": "No faces detected"}
        
        face_encodings = face_recognition.face_encodings(image, face_locations)
        
        results = []
        for face_encoding in face_encodings:
            # Get prediction probabilities
            probabilities = self.model.predict_proba([face_encoding])[0]
            predicted_class = self.model.predict([face_encoding])[0]
            
            # Get class names
            class_names = self.label_encoder.classes_
            
            # Create probability distribution
            prob_dist = {}
            for i, (name, prob) in enumerate(zip(class_names, probabilities)):
                prob_dist[name] = float(prob)
            
            results.append({
                "face_location": face_locations[0],
                "predicted_name": class_names[predicted_class],
                "confidence": float(probabilities[predicted_class]),
                "probability_distribution": prob_dist
            })
        
        # Log access
        self.access_log.append({
            "timestamp": datetime.now().isoformat(),
            "image_path": image_path,
            "results": results
        })
        
        return results

